import{c as s,S as a,j as i,m as t}from"./chunks/framework.DvQr6YbT.js";const g=JSON.parse('{"title":"Install from a URL","description":"","frontmatter":{},"headers":[],"relativePath":"sharing/install-from-url.md","filePath":"sharing/install-from-url.md","lastUpdated":1783409445000}'),l={name:"sharing/install-from-url.md"};function n(o,e,r,h,d,p){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="install-from-a-url" tabindex="-1">Install from a URL <a class="header-anchor" href="#install-from-a-url" aria-label="Permalink to “Install from a URL”">​</a></h1><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/team/kb-bundles/releases/download/v1.2.0/pack.zip</span></span></code></pre></div><p>The bytes are downloaded to a temporary file and then go through <strong>exactly</strong> the same pipeline as a local install — the same preview, the same conformance and version gates, the same path-safety checks. A remote bundle can do nothing a local one couldn&#39;t.</p><p>In Obsidian, the install dialog (Dashboard → Install bundle) accepts the same URLs in its URL field.</p><h2 id="public-sources" tabindex="-1">Public sources <a class="header-anchor" href="#public-sources" aria-label="Permalink to “Public sources”">​</a></h2><p>Any <code>https://</code> URL that serves the zip works: GitHub Release assets on public repos, static file hosts, object storage. Nothing to configure, no GitHub account needed.</p><p>For hosting on a trusted LAN, plain <code>http://</code> works too — Knowlery prints a reminder that the transfer is unencrypted; pair it with <code>--verify</code> when in doubt.</p><h2 id="private-github-sources" tabindex="-1">Private GitHub sources <a class="header-anchor" href="#private-github-sources" aria-label="Permalink to “Private GitHub sources”">​</a></h2><p>If the URL points to a <strong>private</strong> repo&#39;s release, the anonymous download is refused (GitHub reports 404 — it never reveals whether a private repo exists). Knowlery then automatically retries through your own <code>gh</code> CLI login and tells you it did:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Anonymous fetch was refused — retrieved via your gh login instead.</span></span></code></pre></div><p>Requirements: you have read access to the repo (a collaborator invite, or org membership), and <code>gh</code> is installed and logged in (<code>gh auth login</code>).</p><p><strong>Without <code>gh</code></strong>, use your browser — your logged-in session is the credential:</p><ol><li>Open the release page and download the zip.</li><li><code>knowlery bundle install ~/Downloads/pack.zip</code></li></ol><h2 id="verifying-downloads" tabindex="-1">Verifying downloads <a class="header-anchor" href="#verifying-downloads" aria-label="Permalink to “Verifying downloads”">​</a></h2><p>If the sharer posted a SHA-256 checksum next to the link:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">knowlery</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bundle</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verify</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sha256-3f7a…</span></span></code></pre></div><p>The check runs on the raw downloaded bytes <strong>before anything is unpacked</strong>; a mismatch aborts with both hashes printed and nothing installed. <code>--verify</code> also works with local files — useful for zips forwarded through chat.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to “See also”">​</a></h2><ul><li><a href="./troubleshooting">Troubleshooting sharing</a> — starting with &quot;the link 404s for my teammate&quot;.</li></ul>',19)])])}const k=s(l,[["render",n]]);export{g as __pageData,k as default};
